empty_payload_grace: Duration::from_millis(200),

let grace = self.empty_payload_grace;
self.executor.spawn_blocking(Box::pin(async move {
    if !grace.is_zero() {
        std::thread::sleep(grace);
    }
    let res = builder.build_empty_payload(args);
    let _ = tx.send(res);
}));

fn next_build_attempt(&self, kind: &'static str) -> BuildAttemptInfo {
    BuildAttemptInfo::new(self.next_attempt_id.fetch_add(1, Ordering::Relaxed), kind)
}

pub struct BuildArguments<Attributes, Payload: BuiltPayload> {
    pub best_payload: Option<Payload>,
    pub attempt: BuildAttemptInfo,
}

pub struct BuildAttemptInfo {
    pub id: u64,
    pub kind: &'static str,
}

fn build_empty_payload(
    &self,
    args: BuildArguments<Self::Attributes, Self::BuiltPayload>,
) -> Result<Self::BuiltPayload, PayloadBuilderError>;
